import{_ as e,o as n,c as s,ag as i}from"./chunks/framework.BDReElpY.js";const u=JSON.parse('{"title":"RFC 001: Vex Scientific Systems & AI Extensions (V2)","description":"","frontmatter":{},"headers":[],"relativePath":"archive/silicon/scientific_types.md","filePath":"archive/silicon/scientific_types.md"}'),t={name:"archive/silicon/scientific_types.md"};function o(l,a,p,r,c,d){return n(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="rfc-001-vex-scientific-systems-ai-extensions-v2" tabindex="-1">RFC 001: Vex Scientific Systems &amp; AI Extensions (V2) <a class="header-anchor" href="#rfc-001-vex-scientific-systems-ai-extensions-v2" aria-label="Permalink to &quot;RFC 001: Vex Scientific Systems &amp; AI Extensions (V2)&quot;">​</a></h1><p><strong>Status:</strong> Approved (Roadmap) <strong>Date:</strong> 2025-12-20 <strong>Version:</strong> Draft 1</p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>This RFC proposes the addition of three specialized built-in types to the Vex language core to support its vision as a &quot;Scientific Systems Language&quot;:</p><ol><li><code>Tensor&lt;T, Rank&gt;</code> for Machine Learning and High-Performance Computing.</li><li><code>Complex&lt;T&gt;</code> for Engineering and Signal Processing.</li><li><code>Decimal</code> for Financial Systems (Fintech).</li></ol><h2 id="_1-built-in-tensor-tensor-t-rank" tabindex="-1">1. Built-in Tensor (<code>Tensor&lt;T, Rank&gt;</code>) <a class="header-anchor" href="#_1-built-in-tensor-tensor-t-rank" aria-label="Permalink to &quot;1. Built-in Tensor (\`Tensor&lt;T, Rank&gt;\`)&quot;">​</a></h2><h3 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h3><p>Current &quot;Deep Learning&quot; frameworks rely on library-level abstractions (Python/C++ glue) which introduce runtime overhead and prevent compiler-level optimization (loop fusion, tiling). Vex aims to be a native AI language.</p><h3 id="proposal" tabindex="-1">Proposal <a class="header-anchor" href="#proposal" aria-label="Permalink to &quot;Proposal&quot;">​</a></h3><p>A built-in generic type for N-dimensional arrays to serve as the primitive for all Auto-Differentiation (AD) operations.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Type Definition</span></span>
<span class="line"><span>// T: Data type (f32, f16, etc.)</span></span>
<span class="line"><span>// Rank: Number of dimensions (const generic)</span></span>
<span class="line"><span>let t: Tensor&lt;f32, 4&gt; = Tensor.zeros([64, 3, 224, 224])</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Operations (GPU Accelerated / SIMD)</span></span>
<span class="line"><span>// The compiler maps these directly to kernels or BLAS calls</span></span>
<span class="line"><span>let result = input @ weights + bias </span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Autograd (Reverse Mode)</span></span>
<span class="line"><span>// The &#39;autograd&#39; block instructs the compiler to generate the backward pass</span></span>
<span class="line"><span>autograd {</span></span>
<span class="line"><span>    let loss = mse_loss(result, target)</span></span>
<span class="line"><span>    loss.backward() </span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="_2-built-in-complex-numbers-complex-t" tabindex="-1">2. Built-in Complex Numbers (<code>Complex&lt;T&gt;</code>) <a class="header-anchor" href="#_2-built-in-complex-numbers-complex-t" aria-label="Permalink to &quot;2. Built-in Complex Numbers (\`Complex&lt;T&gt;\`)&quot;">​</a></h2><h3 id="motivation-1" tabindex="-1">Motivation <a class="header-anchor" href="#motivation-1" aria-label="Permalink to &quot;Motivation&quot;">​</a></h3><p>Required for Electrical Engineering (AC circuits), Signal Processing (FFT), and Quantum Computing simulations. Library-based implementations often suffer from poor ergonomics and missed SIMD opportunities.</p><h3 id="proposal-1" tabindex="-1">Proposal <a class="header-anchor" href="#proposal-1" aria-label="Permalink to &quot;Proposal&quot;">​</a></h3><p>First-class syntax support and SoA (Structure of Arrays) layout optimization.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Literal Syntax</span></span>
<span class="line"><span>let c: Complex&lt;f64&gt; = 3.0 + 4.0i</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Conjugate and Magnitude</span></span>
<span class="line"><span>let conjugate = c.conj() // 3.0 - 4.0i</span></span>
<span class="line"><span>let mag = c.abs()        // 5.0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Memory Optimization</span></span>
<span class="line"><span>// The compiler can optimize Vec&lt;Complex&lt;T&gt;&gt; into Structure-of-Arrays (SoA)</span></span>
<span class="line"><span>// layouts to maximize SIMD throughput (processing Real and Imag parts in parallel vectors).</span></span></code></pre></div><h2 id="_3-built-in-decimal-decimal" tabindex="-1">3. Built-in Decimal (<code>Decimal</code>) <a class="header-anchor" href="#_3-built-in-decimal-decimal" aria-label="Permalink to &quot;3. Built-in Decimal (\`Decimal\`)&quot;">​</a></h2><h3 id="motivation-2" tabindex="-1">Motivation <a class="header-anchor" href="#motivation-2" aria-label="Permalink to &quot;Motivation&quot;">​</a></h3><p>Floating point arithmetic (<code>f64</code>) is unsuitable for financial calculations due to rounding errors (<code>0.1 + 0.2 != 0.3</code>). Vex, as a systems language, should support robust fintech backend development without requiring external &quot;BigInt&quot; libraries for basic currency math.</p><h3 id="proposal-2" tabindex="-1">Proposal <a class="header-anchor" href="#proposal-2" aria-label="Permalink to &quot;Proposal&quot;">​</a></h3><p>A 128-bit fixed-point decimal type with guaranteed precision and banking rounding modes.</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Literal Syntax (suffix &#39;m&#39; for Money/Decimal)</span></span>
<span class="line"><span>let price: Decimal = 10.50m </span></span>
<span class="line"><span>let tax_rate: Decimal = 0.18m</span></span>
<span class="line"><span></span></span>
<span class="line"><span>let total = price + (price * tax_rate)</span></span>
<span class="line"><span>// Result is strictly precise. No epsilon errors.</span></span></code></pre></div><h2 id="implementation-strategy" tabindex="-1">Implementation Strategy <a class="header-anchor" href="#implementation-strategy" aria-label="Permalink to &quot;Implementation Strategy&quot;">​</a></h2><ol><li><strong>Phase 1 (Parser &amp; Type System)</strong>: Add <code>Tensor</code>, <code>Complex</code>, <code>Decimal</code> keywords and parsing logic.</li><li><strong>Phase 2 (LLVM IR Generation)</strong>: <ul><li><code>Complex</code> -&gt; <code>{ T, T }</code> (LLVM Struct)</li><li><code>Decimal</code> -&gt; <code>i128</code> (Scaled integer)</li><li><code>Tensor</code> -&gt; <code>{ ptr, dims... }</code> (Runtime Descriptor)</li></ul></li><li><strong>Phase 3 (Optimization &amp; Autograd)</strong>: Implement <code>grad</code> support logic for these types and <code>gpu fn</code> mapping for Tensors.</li></ol>`,25)])])}const h=e(t,[["render",o]]);export{u as __pageData,h as default};
